patch:
diff --git a/llvm/lib/Transforms/Scalar/LoopSimplifyCFG.cpp b/llvm/lib/Transforms/Scalar/LoopSimplifyCFG.cpp
index 221094f170ac..cf1544bfd84b 100644
--- a/llvm/lib/Transforms/Scalar/LoopSimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Scalar/LoopSimplifyCFG.cpp
@@ -349,6 +349,16 @@ private:
     // Construct split preheader and the dummy switch to thread edges from it to
     // dead exits.
     BasicBlock *Preheader = L.getLoopPreheader();
+    if (!Preheader) {
+      // Create a dedicated preheader if it does not exist so we can safely
+      // thread edges from it to dead exits.
+      bool PreserveLCSSA = true; // Required to maintain LCSSA form.
+      Preheader = InsertPreheaderForLoop(&L, &DT, &LI, MSSAU, PreserveLCSSA);
+      if (!Preheader) {
+        LLVM_DEBUG(dbgs() << "Give up handling dead exits: failed to create preheader.\n");
+        return;
+      }
+    }
     BasicBlock *NewPreheader = llvm::SplitBlock(
         Preheader, Preheader->getTerminator(), &DT, &LI, MSSAU);

@@ -532,6 +542,16 @@ public:
   bool run() {
     assert(L.getLoopLatch() && "Should be single latch!");

+    // Ensure the loop has a dedicated preheader. Some transformations in this
+    // pass rely on it.
+    if (!L.getLoopPreheader()) {
+      bool PreserveLCSSA = true;
+      if (!InsertPreheaderForLoop(&L, &DT, &LI, MSSAU, PreserveLCSSA)) {
+        LLVM_DEBUG(dbgs() << "LoopSimplifyCFG: failed to create preheader, giving up.\n");
+        return false;
+      }
+    }
+
     // Collect all available information about status of blocks after constant
     // folding.
     analyze();

